// Look for 'log' in the main object OR in the 'body' folder
const rawLog = $json.log || ($json.body ? $json.body.log : "") || "";

if (!rawLog) {
  return { log: "NO_DATA_RECEIVED" }; // Help us debug if it's still empty
}

// Clean the log
let cleaned = rawLog.replace(/\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}/, ''); 
cleaned = cleaned.replace(/(INFO|WARN|ERROR|CRITICAL|DEBUG|TRACE)/i, '');
cleaned = cleaned.replace(/[\|\s]{2,}/g, ' '); 

return { log: cleaned.trim() };
